package ccxtpro
import ccxt "github.com/ccxt/ccxt/go/v4"
type Rubin struct {
   *RubinCore
   Core *RubinCore
   exchangeTyped *ccxt.Rubin
}

func NewRubin(userConfig map[string]any) *Rubin {
   p := NewRubinCore()
   p.Init(userConfig)
   return &Rubin{
       RubinCore: p,
       Core:  p,
       exchangeTyped: ccxt.NewRubinFromCore(p.base),
   }
}


